import React, { useState, useEffect } from 'react';

const Consultation = ({ userRole }) => {
  const [medicalRecords, setMedicalRecords] = useState([]);
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [patientSummary, setPatientSummary] = useState(null);
  const [formData, setFormData] = useState({
    patient_id: '',
    visit_date: new Date().toISOString().split('T')[0],
    chief_complaint: '',
    diagnosis: '',
    treatment_plan: '',
    notes: '',
    vital_signs: {
      blood_pressure_systolic: '',
      blood_pressure_diastolic: '',
      heart_rate: '',
      temperature: '',
      weight: '',
      height: '',
      oxygen_saturation: '',
      respiratory_rate: ''
    }
  });

  useEffect(() => {
    fetchMedicalRecords();
    if (userRole === 'doctor' || userRole === 'receptionist') {
      fetchPatients();
    }
  }, []);

  const fetchMedicalRecords = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/medical-records/search?limit=20', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setMedicalRecords(data);
    } catch (error) {
      console.error('Error fetching medical records:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchPatients = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/patients', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setPatients(data.patients || []);
    } catch (error) {
      console.error('Error fetching patients:', error);
    }
  };

  const fetchPatientSummary = async (patientId) => {
    try {
      const response = await fetch(`http://localhost:5000/api/medical-records/summary/${patientId}`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setPatientSummary(data);
    } catch (error) {
      console.error('Error fetching patient summary:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:5000/api/medical-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(formData)
      });

      if (response.ok) {
        setShowModal(false);
        fetchMedicalRecords();
        setFormData({
          patient_id: '',
          visit_date: new Date().toISOString().split('T')[0],
          chief_complaint: '',
          diagnosis: '',
          treatment_plan: '',
          notes: '',
          vital_signs: {
            blood_pressure_systolic: '',
            blood_pressure_diastolic: '',
            heart_rate: '',
            temperature: '',
            weight: '',
            height: '',
            oxygen_saturation: '',
            respiratory_rate: ''
          }
        });
      }
    } catch (error) {
      console.error('Error creating medical record:', error);
    }
  };

  const handlePatientSelect = (patientId) => {
    const patient = patients.find(p => p.id === patientId);
    setSelectedPatient(patient);
    if (patientId) {
      fetchPatientSummary(patientId);
      setFormData({...formData, patient_id: patientId});
    } else {
      setPatientSummary(null);
    }
  };

  const handleVitalSignChange = (field, value) => {
    setFormData({
      ...formData,
      vital_signs: {
        ...formData.vital_signs,
        [field]: value
      }
    });
  };

  if (loading) {
    return <div className="flex justify-center items-center h-64">Loading consultation records...</div>;
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Consultation & Medical Records</h2>
        {userRole === 'doctor' && (
          <button
            onClick={() => setShowModal(true)}
            className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition-colors"
          >
            New Consultation
          </button>
        )}
      </div>

      {/* Patient Summary Card */}
      {patientSummary && (
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <div className="flex justify-between items-start mb-4">
            <div>
              <h3 className="text-lg font-semibold text-gray-800">
                {patientSummary.patient.first_name} {patientSummary.patient.last_name}
              </h3>
              <p className="text-sm text-gray-600">ID: {patientSummary.patient.patient_id}</p>
              <p className="text-sm text-gray-600">
                DOB: {new Date(patientSummary.patient.date_of_birth).toLocaleDateString()} | 
                Gender: {patientSummary.patient.gender} | 
                Blood Type: {patientSummary.patient.blood_type || 'N/A'}
              </p>
            </div>
            <button
              onClick={() => {
                setSelectedPatient(null);
                setPatientSummary(null);
              }}
              className="text-gray-500 hover:text-gray-700"
            >
              ✕
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="border-l-4 border-blue-500 pl-4">
              <h4 className="font-medium text-gray-700 mb-2">Medical History</h4>
              <p className="text-sm text-gray-600">
                {patientSummary.patient.medical_history || 'No recorded medical history'}
              </p>
              <p className="text-sm text-gray-600 mt-1">
                Allergies: {patientSummary.patient.allergies || 'None recorded'}
              </p>
            </div>

            <div className="border-l-4 border-green-500 pl-4">
              <h4 className="font-medium text-gray-700 mb-2">Active Prescriptions</h4>
              {patientSummary.active_prescriptions.length > 0 ? (
                <div className="space-y-1">
                  {patientSummary.active_prescriptions.slice(0, 3).map((prescription) => (
                    <p key={prescription.id} className="text-sm text-gray-600">
                      {prescription.medication_name} - {prescription.dosage}
                    </p>
                  ))}
                  {patientSummary.active_prescriptions.length > 3 && (
                    <p className="text-xs text-gray-500">...and {patientSummary.active_prescriptions.length - 3} more</p>
                  )}
                </div>
              ) : (
                <p className="text-sm text-gray-600">No active prescriptions</p>
              )}
            </div>

            <div className="border-l-4 border-purple-500 pl-4">
              <h4 className="font-medium text-gray-700 mb-2">Recent Visits</h4>
              {patientSummary.medical_records.length > 0 ? (
                <div className="space-y-1">
                  {patientSummary.medical_records.slice(0, 3).map((record) => (
                    <p key={record.id} className="text-sm text-gray-600">
                      {new Date(record.visit_date).toLocaleDateString()} - {record.chief_complaint}
                    </p>
                  ))}
                  {patientSummary.medical_records.length > 3 && (
                    <p className="text-xs text-gray-500">...and {patientSummary.medical_records.length - 3} more</p>
                  )}
                </div>
              ) : (
                <p className="text-sm text-gray-600">No previous visits</p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Medical Records Table */}
      <div className="bg-white rounded-lg shadow-md overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Date
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Patient
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Chief Complaint
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Diagnosis
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Doctor
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {medicalRecords.map((record) => (
                <tr key={record.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {new Date(record.visit_date).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div>
                      <div className="text-sm font-medium text-gray-900">
                        {record.patient_first_name} {record.patient_last_name}
                      </div>
                      <div className="text-sm text-gray-500">{record.patient_id}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-900">
                    {record.chief_complaint.length > 50 
                      ? record.chief_complaint.substring(0, 50) + '...'
                      : record.chief_complaint
                    }
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-900">
                    {record.diagnosis ? (
                      record.diagnosis.length > 50 
                        ? record.diagnosis.substring(0, 50) + '...'
                        : record.diagnosis
                    ) : (
                      <span className="text-gray-400">No diagnosis</span>
                    )}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {record.doctor_first_name && record.doctor_last_name 
                      ? `Dr. ${record.doctor_first_name} ${record.doctor_last_name}`
                      : 'Unknown'
                    }
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <button
                      onClick={() => handlePatientSelect(record.patient_id)}
                      className="text-blue-600 hover:text-blue-900"
                    >
                      View Details
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* New Consultation Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-4xl max-h-screen overflow-y-auto">
            <h3 className="text-lg font-semibold mb-4">New Consultation</h3>
            <form onSubmit={handleSubmit}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Patient
                  </label>
                  <select
                    value={formData.patient_id}
                    onChange={(e) => handlePatientSelect(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  >
                    <option value="">Select Patient</option>
                    {patients.map((patient) => (
                      <option key={patient.id} value={patient.id}>
                        {patient.first_name} {patient.last_name} ({patient.patient_id})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Visit Date
                  </label>
                  <input
                    type="date"
                    value={formData.visit_date}
                    onChange={(e) => setFormData({...formData, visit_date: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Chief Complaint
                  </label>
                  <textarea
                    value={formData.chief_complaint}
                    onChange={(e) => setFormData({...formData, chief_complaint: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="2"
                    placeholder="Main reason for visit"
                    required
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Diagnosis
                  </label>
                  <textarea
                    value={formData.diagnosis}
                    onChange={(e) => setFormData({...formData, diagnosis: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="3"
                    placeholder="Clinical diagnosis"
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Treatment Plan
                  </label>
                  <textarea
                    value={formData.treatment_plan}
                    onChange={(e) => setFormData({...formData, treatment_plan: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="3"
                    placeholder="Treatment recommendations"
                  />
                </div>

                <div className="md:col-span-2">
                  <h4 className="font-medium text-gray-700 mb-2">Vital Signs (Optional)</h4>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">BP Systolic</label>
                      <input
                        type="number"
                        value={formData.vital_signs.blood_pressure_systolic}
                        onChange={(e) => handleVitalSignChange('blood_pressure_systolic', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="120"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">BP Diastolic</label>
                      <input
                        type="number"
                        value={formData.vital_signs.blood_pressure_diastolic}
                        onChange={(e) => handleVitalSignChange('blood_pressure_diastolic', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="80"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">Heart Rate</label>
                      <input
                        type="number"
                        value={formData.vital_signs.heart_rate}
                        onChange={(e) => handleVitalSignChange('heart_rate', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="72"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">Temperature</label>
                      <input
                        type="number"
                        step="0.1"
                        value={formData.vital_signs.temperature}
                        onChange={(e) => handleVitalSignChange('temperature', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="36.5"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">Weight (kg)</label>
                      <input
                        type="number"
                        step="0.1"
                        value={formData.vital_signs.weight}
                        onChange={(e) => handleVitalSignChange('weight', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="70"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">Height (cm)</label>
                      <input
                        type="number"
                        value={formData.vital_signs.height}
                        onChange={(e) => handleVitalSignChange('height', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="170"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">SpO2 (%)</label>
                      <input
                        type="number"
                        value={formData.vital_signs.oxygen_saturation}
                        onChange={(e) => handleVitalSignChange('oxygen_saturation', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="98"
                      />
                    </div>
                    <div>
                      <label className="block text-xs text-gray-600 mb-1">Resp. Rate</label>
                      <input
                        type="number"
                        value={formData.vital_signs.respiratory_rate}
                        onChange={(e) => handleVitalSignChange('respiratory_rate', e.target.value)}
                        className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        placeholder="16"
                      />
                    </div>
                  </div>
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Notes
                  </label>
                  <textarea
                    value={formData.notes}
                    onChange={(e) => setFormData({...formData, notes: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="3"
                    placeholder="Additional notes..."
                  />
                </div>
              </div>

              <div className="flex justify-end space-x-3 mt-6">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-4 py-2 text-gray-700 border border-gray-300 rounded-md hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600"
                >
                  Save Consultation
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Consultation;
